export interface EquipItem {
  id: string
  category: EquipCategory
  name: string
  cost: string
  weight: string
  props: string
  /** weapons only: true for ranged — draws a divider inside the weapon section */
  ranged?: boolean
  /** armor only: subgroup for dividers inside the armor section */
  tier?: ArmorTier
  /** mounts only: subgroup for dividers inside the transport section */
  mountTier?: MountTier
  /** weapons only: 2024 weapon-mastery property */
  mastery?: MasteryKey
}

