let _i = 0
const w = (
  category: EquipCategory,
  name: string,
  cost: string,
  weight: string,
  props: string,
  ranged = false,
  mastery?: MasteryKey
): EquipItem => ({ id: `eq-${_i++}`, category, name, cost, weight, props, ranged, mastery })

const a = (name: string, cost: string, weight: string, props: string, tier: ArmorTier): EquipItem => ({
  id: `eq-${_i++}`,
  category: 'armor',
  name,
  cost,
  weight,
  props,
  tier
})

const m = (name: string, cost: string, weight: string, props: string, mountTier: MountTier): EquipItem => ({
  id: `eq-${_i++}`,
  category: 'mounts',
  name,
  cost,
  weight,
  props,
  mountTier
})

